class Admin::LogsController < ApplicationController
  before_action :require_admin!

  def show
    filename = params[:log].to_s
    path = Rails.root.join("log", filename)
    @log_content = File.read(path)
    render plain: @log_content, content_type: "text/plain"
  end

  private

  def require_admin!
    return if current_user&.admin?

    head :forbidden
  end
end